mapper.insert:
insert into notice (btitle, bcontent, emp_id, com_id
  , bfile
)
values (#{btitle}, #{bcontent}, #{empId}, #{comId}
  , #{bfile}
)

mapper.update:
update notice
set btitle   = #{btitle}
    , bcontent = #{bcontent}
    , bfile = #{bfile}
where bno = #{bno}

mapper.select:
select count(*) from notice where com_id = #{comId}
and bno not in
#{bno}
and (lower(btitle) like lower('%' || #{keyword} || '%') or lower(bcontent) like lower('%' || #{keyword} || '%'))
